// Unpack peels one layer: Promise → T, () => T → T, T[] → T, else T
type Unpack<T> =
  T extends Promise<infer U>            ? U :
  T extends (...args: any[]) => infer U ? U :
  T extends (infer U)[]                 ? U :
  T;

// --- examples ---
