// Recursively unwrap Promise<Promise<Promise<T>>> to T
type Awaited_<T> =
  T extends null | undefined ? T :
  T extends object & { then(onfulfilled: infer F, ...args: any[]): any }
    ? F extends (value: infer V, ...args: any[]) => any
      ? Awaited_<V>
      : never
    : T;

// (Note: modern TS has built-in `Awaited<T>` — this shows the mechanics)

// Utility that accepts any nesting depth
async function deepAwait<T>(value: T): Promise<Awaited<T>> {
  let v: unknown = value;
  while (v instanceof Promise) {
    v = await v;
  }
  return v as Awaited<T>;
}

// --- conditional type for async function return types ---
type AsyncReturnType<T extends (...args: any[]) => Promise<any>> =
  Awaited<ReturnType<T>>;

async function fetchConfig(): Promise<{ port: number; host: string }> {
  return { port: 3000, host: 'localhost' };
}

type Config = AsyncReturnType<typeof fetchConfig>;
// { port: number; host: string }

// Practical: type-safe parallel fetch
async function parallel<T extends readonly (() => Promise<unknown>)[]>(
  fns: T
): Promise<{ [K in keyof T]: Awaited<ReturnType<T[K]>> }> {
  return Promise.all(fns.map(f => f())) as any;
}

// Usage
const [user, posts] = await parallel([
  () => fetch('/api/user').then(r => r.json()) as Promise<{id:string}>,
  () => fetch('/api/posts').then(r => r.json()) as Promise<{id:string}[]>,
]);
// user: {id:string}, posts: {id:string}[]
