// TypeScript lacks true HKTs, but we simulate them via a 'URI' registry
declare module './hkt' {
  interface URItoKind<A> {
    Maybe:  Maybe<A>;
    List:   A[];
  }
}

type URIS = keyof URItoKind<unknown>;
type Kind<F extends URIS, A> = URItoKind<A>[F];

// Functor typeclass
interface Functor<F extends URIS> {
  map<A, B>(fa: Kind<F, A>, f: (a: A) => B): Kind<F, B>;
}

// --- Maybe monad ---
type Maybe<A> = { _tag: 'Just'; value: A } | { _tag: 'Nothing' };

const just    = <A>(value: A): Maybe<A> => ({ _tag: 'Just', value });
const nothing = <A>(): Maybe<A>         => ({ _tag: 'Nothing' });

const MaybeFunctor: Functor<'Maybe'> = {
  map<A, B>(fa: Maybe<A>, f: (a: A) => B): Maybe<B> {
    return fa._tag === 'Nothing' ? nothing() : just(f(fa.value));
  }
};

const ListFunctor: Functor<'List'> = {
  map: <A, B>(fa: A[], f: (a: A) => B): B[] => fa.map(f)
};

// Generic function that works with ANY Functor instance
function lift<F extends URIS, A, B>(
  F: Functor<F>,
  fa: Kind<F, A>,
  f: (a: A) => B
): Kind<F, B> {
  return F.map(fa, f);
}

// Usage
const doubled = lift(MaybeFunctor, just(21), x => x * 2);
// { _tag: 'Just', value: 42 }

const none = lift(MaybeFunctor, nothing<number>(), x => x * 2);
// { _tag: 'Nothing' }

const nums = lift(ListFunctor, [1, 2, 3], x => x * 2);
// [2, 4, 6]
