// Keep only keys where the value type extends V
type PickByValue<T, V> = {
  [K in keyof T as T[K] extends V ? K : never]: T[K];
};

// Inverse: omit keys where value extends V
type OmitByValue<T, V> = {
  [K in keyof T as T[K] extends V ? never : K]: T[K];
};

// --- examples ---
interface Entity {
  id:        number;
  name:      string;
  email:     string;
  isActive:  boolean;
  createdAt: Date;
  updatedAt: Date;
  score:     number;
}

type StringFields  = PickByValue<Entity, string>;  // { name: string; email: string }
type NumberFields  = PickByValue<Entity, number>;  // { id: number; score: number }
type DateFields    = PickByValue<Entity, Date>;    // { createdAt: Date; updatedAt: Date }
type NonStrings    = OmitByValue<Entity, string>;  // everything except name/email

// Practical use: build a search filter only over string fields
function searchByStringField<T>(
  items: T[],
  field: keyof PickByValue<T, string>,
  query: string
): T[] {
  return items.filter(item =>
    String(item[field as keyof T]).toLowerCase().includes(query.toLowerCase())
  );
}

