import type { Request, Response, NextFunction } from 'express';

// Extract the parameter types of each handler in a variadic middleware tuple
type MiddlewareParams<T> = T extends (req: infer R, res: infer S, next: infer N) => any
  ? [R, S, N]
  : never;

// Infer async handler return
type HandlerReturn<T> = T extends (...args: any[]) => infer R
  ? R extends Promise<infer U> ? U : R
  : never;

// Type a middleware factory that captures injected dependency types
type MiddlewareFactory<Deps extends Record<string, unknown>> = (
  deps: Deps
) => (req: Request, res: Response, next: NextFunction) => void | Promise<void>;

// Infer Deps from a factory function
type FactoryDeps<F> = F extends MiddlewareFactory<infer D> ? D : never;

// --- concrete example ---
const authMiddleware: MiddlewareFactory<{ secret: string; issuer: string }> =
  ({ secret, issuer }) =>
  async (req, _res, next) => {
    const token = req.headers.authorization?.split(' ')[1];
    if (!token) throw Object.assign(new Error('Unauthorized'), { status: 401 });
    // validate token with secret/issuer...
    next();
  };

type AuthDeps = FactoryDeps<typeof authMiddleware>;
// { secret: string; issuer: string }

// Compose multiple typed factories
function composeMiddleware<T extends Record<string, unknown>>(
  factories: MiddlewareFactory<T>[],
  deps: T
) {
  return factories.map(f => f(deps));
}

const middlewares = composeMiddleware(
  [authMiddleware],
  { secret: 'abc', issuer: 'my-app' }
);
