/**
 * Semaphore that limits concurrent async operations.
 */
class Semaphore {
  #permits;
  #queue = [];

  constructor(permits) {
    this.#permits = permits;
  }

  async acquire() {
    if (this.#permits > 0) {
      this.#permits--;
      return;
    }
    await new Promise(resolve => this.#queue.push(resolve));
  }

  release() {
    if (this.#queue.length > 0) {
      this.#queue.shift()();
    } else {
      this.#permits++;
    }
  }
}

/**
 * Map items through an async function with at most `concurrency` parallel calls.
 * @template T, R
 * @param {T[]} items
 * @param {(item: T, index: number) => Promise<R>} fn
 * @param {number} concurrency
 * @returns {Promise<R[]>}
 */
async function mapConcurrent(items, fn, concurrency = 10) {
  const sem = new Semaphore(concurrency);
  return Promise.all(
    items.map(async (item, i) => {
      await sem.acquire();
      try {
        return await fn(item, i);
      } finally {
        sem.release();
      }
    })
  );
}

// --- usage: resize 1000 images, 5 at a time ---
const imagePaths = Array.from({ length: 1000 }, (_, i) => `/img/${i}.png`);

const results = await mapConcurrent(imagePaths, async (path) => {
  const res = await fetch(`/resize?src=${encodeURIComponent(path)}`);
  return res.json();
}, 5);

console.log(`Processed ${results.length} images`);

// --- variant: process with per-item error isolation ---
async function mapConcurrentSettled(items, fn, concurrency = 10) {
  const sem = new Semaphore(concurrency);
  return Promise.allSettled(
    items.map(async (item) => {
      await sem.acquire();
      try   { return await fn(item); }
      finally { sem.release(); }
    })
  );
}
