/**
 * Fetch with exponential backoff + full jitter retry.
 *
 * @param {string|URL} url
 * @param {RequestInit & {
 *   maxRetries?: number;
 *   baseDelay?: number;
 *   maxDelay?: number;
 *   retryOn?: number[];
 *   signal?: AbortSignal;
 * }} options
 */
async function fetchWithRetry(url, options = {}) {
  const {
    maxRetries = 4,
    baseDelay  = 500,
    maxDelay   = 30_000,
    retryOn    = [429, 500, 502, 503, 504],
    signal,
    ...fetchOptions
  } = options;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    if (signal?.aborted) throw new DOMException('Aborted', 'AbortError');

    const response = await fetch(url, { ...fetchOptions, signal });

    if (response.ok || !retryOn.includes(response.status) || attempt === maxRetries) {
      return response;
    }

    // Respect Retry-After header (seconds or HTTP-date)
    let delay;
    const retryAfter = response.headers.get('Retry-After');
    if (retryAfter) {
      const seconds = Number(retryAfter);
      delay = isNaN(seconds)
        ? new Date(retryAfter).getTime() - Date.now()
        : seconds * 1000;
    } else {
      // Exponential backoff + full jitter: random in [0, min(cap, base * 2^attempt)]
      const cap      = Math.min(maxDelay, baseDelay * 2 ** attempt);
      delay          = Math.random() * cap;
    }

    delay = Math.max(0, delay);
    console.warn(`Attempt ${attempt + 1} failed (${response.status}). Retrying in ${Math.round(delay)}ms…`);

    await new Promise((resolve, reject) => {
      const t = setTimeout(resolve, delay);
      signal?.addEventListener('abort', () => {
        clearTimeout(t);
        reject(new DOMException('Aborted', 'AbortError'));
      }, { once: true });
    });
  }
}

// --- usage ---
const controller = new AbortController();
const response   = await fetchWithRetry('https://api.example.com/data', {
  maxRetries: 5,
  baseDelay:  300,
  signal:     controller.signal,
});
const data = await response.json();
