const MIRRORS = [
  'https://mirror1.api.com/data',
  'https://mirror2.api.com/data',
  'https://mirror3.api.com/data',
];

/**
 * Fetch from multiple mirrors simultaneously.
 * - Returns the FASTEST successful response (Promise.any)
 * - After resolution, collects and logs failures (Promise.allSettled)
 */
async function fetchFromMirrors(mirrors, options = {}) {
  const controller  = new AbortController();
  const { signal }  = controller;

  // Each fetch races — cancel all once one wins
  const fetchPromises = mirrors.map(url =>
    fetch(url, { ...options, signal }).then(async res => {
      if (!res.ok) throw new Error(`${url} → HTTP ${res.status}`);
      return { url, data: await res.json() };
    })
  );

  try {
    // Promise.any: resolves with first success, rejects only if ALL fail
    const winner = await Promise.any(fetchPromises);
    controller.abort(); // cancel remaining in-flight requests
    return winner;
  } catch (aggregateError) {
    // All mirrors failed — AggregateError contains all rejection reasons
    const report = aggregateError.errors
      .map((e, i) => `  Mirror ${i + 1}: ${e.message}`)
      .join('\n');
    throw new Error(`All mirrors failed:\n${report}`);
  } finally {
    // In parallel: collect detailed status of every mirror for observability
    Promise.allSettled(fetchPromises).then(results => {
      results.forEach((r, i) => {
        if (r.status === 'rejected') {
          console.error(`Mirror ${mirrors[i]} failed:`, r.reason?.message);
        }
      });
    });
  }
}

// Usage with timeout via Promise.race
async function fetchWithTimeout(mirrors, ms = 5000) {
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`Timeout after ${ms}ms`)), ms)
  );
  return Promise.race([fetchFromMirrors(mirrors), timeout]);
}

const { url, data } = await fetchWithTimeout(MIRRORS, 3000);
console.log(`Got response from ${url}:`, data);
