/**
 * Parse NDJSON from a ReadableStream of Uint8Array chunks.
 * Yields one parsed object per line without buffering the whole stream.
 */
function createNDJSONStream(readable) {
  const decoder = new TextDecoder();
  let buffer    = '';

  const transform = new TransformStream({
    transform(chunk, controller) {
      buffer += decoder.decode(chunk, { stream: true });

      const lines = buffer.split('\n');
      // Keep the last (potentially incomplete) line in the buffer
      buffer = lines.pop() ?? '';

      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue; // skip blank lines
        try {
          controller.enqueue(JSON.parse(trimmed));
        } catch (e) {
          controller.error(new SyntaxError(`Invalid JSON line: ${trimmed}`));
        }
      }
    },
    flush(controller) {
      // Handle final line without trailing newline
      const trimmed = buffer.trim();
      if (trimmed) {
        try {
          controller.enqueue(JSON.parse(trimmed));
        } catch {
          controller.error(new SyntaxError(`Invalid JSON in final chunk: ${trimmed}`));
        }
      }
    },
  });

  return readable.pipeThrough(transform);
}

// --- usage: stream 10M rows from an API ---
const response = await fetch('/api/export/users');
if (!response.ok || !response.body) throw new Error('Bad response');

const jsonStream = createNDJSONStream(response.body);
const reader     = jsonStream.getReader();

let count = 0;
try {
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    count++;
    // Process each user object as it arrives
    console.log(value.id, value.email);
  }
} finally {
  reader.releaseLock();
}
console.log(`Streamed ${count} records`);
