class DatabaseCursor {
  #query;
  #batchSize;
  #offset = 0;
  #buffer = [];
  #exhausted = false;
  #closed = false;

  constructor(query, batchSize = 100) {
    this.#query     = query;
    this.#batchSize = batchSize;
  }

  // Implement the async iterator protocol
  [Symbol.asyncIterator]() {
    return this;
  }

  async next() {
    if (this.#closed) return { value: undefined, done: true };

    // Refill buffer when empty
    if (this.#buffer.length === 0) {
      if (this.#exhausted) return { value: undefined, done: true };
      await this.#fetchBatch();
    }

    if (this.#buffer.length === 0) return { value: undefined, done: true };

    return { value: this.#buffer.shift(), done: false };
  }

  // Called when consumer breaks early (for await...of break / return)
  async return(value) {
    await this.#close();
    return { value, done: true };
  }

  async throw(error) {
    await this.#close();
    throw error;
  }

  async #fetchBatch() {
    const rows = await simulateDbQuery(this.#query, this.#offset, this.#batchSize);
    this.#buffer.push(...rows);
    this.#offset   += rows.length;
    this.#exhausted = rows.length < this.#batchSize;
  }

  async #close() {
    if (!this.#closed) {
      this.#closed = true;
      this.#buffer  = [];
      // Release DB resources here
      console.log('Cursor closed');
    }
  }
}

