import { EventEmitter } from 'events';

/**
 * @param {() => Promise<any>} fn
 * @param {{ retries?: number, timeout?: number, backoff?: (n: number) => number }} opts
 * @returns {{ promise: Promise<any>, emitter: EventEmitter }}
 */
function withRetry(fn, opts = {}) {
  const {
    retries = 3,
    timeout = 5_000,
    backoff = n => Math.min(1000 * 2 ** n, 30_000),
  } = opts;

  const emitter = new EventEmitter();

  const promise = (async () => {
    let lastError;
    for (let attempt = 0; attempt <= retries; attempt++) {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), timeout);

      emitter.emit('attempt', { attempt, total: retries + 1 });

      try {
        const result = await Promise.race([
          fn(controller.signal),
          new Promise((_, reject) =>
            controller.signal.addEventListener('abort', () =>
              reject(new Error(`Attempt ${attempt} timed out after ${timeout}ms`))
            )
          ),
        ]);
        clearTimeout(timer);
        emitter.emit('success', { attempt, result });
        return result;
      } catch (err) {
        clearTimeout(timer);
        lastError = err;
        emitter.emit('failure', { attempt, error: err });

        if (attempt < retries) {
          const delay = backoff(attempt);
          emitter.emit('retry', { attempt, delay });
          await new Promise(r => setTimeout(r, delay));
        }
      }
    }
    emitter.emit('giveup', { error: lastError });
    throw lastError;
  })();

  return { promise, emitter };
}

// Usage
const { promise, emitter } = withRetry(
  signal => fetch('/api/data', { signal }).then(r => r.json()),
  { retries: 4, timeout: 3000 }
);

emitter.on('attempt', ({ attempt }) => console.log(`Attempt ${attempt + 1}…`));
emitter.on('retry',   ({ delay })   => console.log(`Retrying in ${delay}ms`));
emitter.on('giveup',  ({ error })   => console.error('Gave up:', error.message));

const data = await promise;
