class LazyRange {
  #start; #stop; #step; #transforms;

  constructor(start, stop, step = 1, transforms = []) {
    this.#start      = start;
    this.#stop       = stop;
    this.#step       = step;
    this.#transforms = transforms;
  }

  // Lazy map — chains a transform without running anything
  map(fn) {
    return new LazyRange(this.#start, this.#stop, this.#step,
      [...this.#transforms, { type: 'map', fn }]);
  }

  // Lazy filter
  filter(pred) {
    return new LazyRange(this.#start, this.#stop, this.#step,
      [...this.#transforms, { type: 'filter', pred }]);
  }

  // Apply the transform pipeline to a single value
  #apply(value) {
    let v = value;
    let skip = false;
    for (const t of this.#transforms) {
      if (t.type === 'map')    { v = t.fn(v); }
      if (t.type === 'filter') { if (!t.pred(v)) { skip = true; break; } }
    }
    return { v, skip };
  }

  // Synchronous iterator
  [Symbol.iterator]() {
    let current = this.#start;
    const stop  = this.#stop;
    const step  = this.#step;
    const apply = this.#apply.bind(this);

    return {
      next() {
        while (current < stop) {
          const raw = current;
          current += step;
          const { v, skip } = apply(raw);
          if (!skip) return { value: v, done: false };
        }
        return { value: undefined, done: true };
      },
      [Symbol.iterator]() { return this; },
    };
  }

  // Async iterator — simulates async data source
  async *[Symbol.asyncIterator]() {
    for (const value of this) {
      await new Promise(r => setImmediate(r)); // yield event loop turn
      yield value;
    }
  }

  toArray() { return [...this]; }
  first()   { return this[Symbol.iterator]().next().value; }
}

// Factory
const range = (start, stop, step) => new LazyRange(start, stop, step);

// --- usage ---
const evens = range(0, 20)
  .filter(n => n % 2 === 0)
  .map(n => n * n);

console.log(evens.toArray()); // [0, 4, 16, 36, 64, 100, 144, 196, 256, 324]
console.log(evens.first());   // 0

// Async
for await (const v of range(0, 5).map(n => n * 2)) {
  console.log(v); // 0, 2, 4, 6, 8
}
