import { spawn } from 'child_process';
import { EventEmitter } from 'events';

class ProcessManager extends EventEmitter {
  #processes = new Map();

  /**
   * Register and start a managed process.
   * @param {string} name
   * @param {string} cmd
   * @param {string[]} args
   * @param {{ maxRestarts?: number, restartDelay?: number, cwd?: string, env?: object }} opts
   */
  spawn(name, cmd, args = [], opts = {}) {
    const { maxRestarts = 5, restartDelay = 1000, cwd, env } = opts;
    const state = { restarts: 0, proc: null };
    this.#processes.set(name, state);
    this.#start(name, cmd, args, { maxRestarts, restartDelay, cwd, env });
    return this;
  }

  #start(name, cmd, args, opts) {
    const { maxRestarts, restartDelay, cwd, env } = opts;
    const state = this.#processes.get(name);

    const proc = spawn(cmd, args, {
      cwd,
      env: { ...process.env, ...env },
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    state.proc = proc;

    const prefix = buf => `[${name}:${proc.pid}] ${buf.toString().trimEnd()}`;

    proc.stdout.on('data', buf => {
      const line = prefix(buf);
      this.emit('log', { name, level: 'info', line });
      process.stdout.write(line + '\n');
    });
    proc.stderr.on('data', buf => {
      const line = prefix(buf);
      this.emit('log', { name, level: 'error', line });
      process.stderr.write(line + '\n');
    });

    proc.on('exit', (code, signal) => {
      this.emit('exit', { name, code, signal });

      if (state.restarts >= maxRestarts) {
        this.emit('failed', { name, restarts: state.restarts });
        console.error(`[manager] ${name} exceeded max restarts (${maxRestarts}) — giving up`);
        return;
      }
      state.restarts++;
      console.warn(`[manager] ${name} exited (code=${code}). Restart ${state.restarts}/${maxRestarts} in ${restartDelay}ms`);
      setTimeout(() => this.#start(name, cmd, args, opts), restartDelay);
    });

    this.emit('spawn', { name, pid: proc.pid });
  }

  kill(name, signal = 'SIGTERM') {
    const state = this.#processes.get(name);
    state?.proc?.kill(signal);
  }

  killAll(signal = 'SIGTERM') {
    for (const name of this.#processes.keys()) this.kill(name, signal);
  }
}

// --- usage ---
const pm = new ProcessManager();

pm.on('log',    ({ name, level, line }) => { /* ship to log aggregator */ });
pm.on('failed', ({ name }) => console.error(`ALERT: ${name} is down permanently`));

pm.spawn('api-server',  'node', ['server.js'],  { maxRestarts: 10, restartDelay: 2000 });
pm.spawn('job-worker',  'node', ['worker.js'],  { maxRestarts: 5 });
pm.spawn('file-watcher','node', ['watcher.js'], { maxRestarts: 3 });

process.on('SIGINT', () => { pm.killAll(); process.exit(0); });
