import { createReadStream, createWriteStream } from 'fs';
import { pipeline, Transform } from 'stream';
import { pipeline as pipelineP }  from 'stream/promises';

// Stage 1: CSV text → row objects
class CSVParser extends Transform {
  #headers = null;
  #buffer  = '';
  #sep;

  constructor(sep = ',') {
    super({ objectMode: true });
    this.#sep = sep;
  }

  _transform(chunk, _, cb) {
    this.#buffer += chunk.toString();
    const lines = this.#buffer.split('\n');
    this.#buffer = lines.pop() ?? '';

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      const cols = trimmed.split(this.#sep);
      if (!this.#headers) { this.#headers = cols; continue; }
      const row = Object.fromEntries(this.#headers.map((h, i) => [h, cols[i] ?? '']));
      this.push(row);
    }
    cb();
  }

  _flush(cb) {
    if (this.#buffer.trim() && this.#headers) {
      const cols = this.#buffer.split(this.#sep);
      this.push(Object.fromEntries(this.#headers.map((h, i) => [h, cols[i] ?? ''])));
    }
    cb();
  }
}

// Stage 2: Type-cast and enrich
class RowTransformer extends Transform {
  constructor() { super({ objectMode: true }); }

  _transform(row, _, cb) {
    this.push({
      id:        parseInt(row.id, 10),
      name:      row.name?.trim(),
      revenue:   parseFloat(row.revenue ?? '0'),
      active:    row.active?.toLowerCase() === 'true',
      importedAt: new Date().toISOString(),
    });
    cb();
  }
}

// Stage 3: Filter
class RowFilter extends Transform {
  #pred;
  constructor(pred) { super({ objectMode: true }); this.#pred = pred; }
  _transform(row, _, cb) {
    if (this.#pred(row)) this.push(row);
    cb();
  }
}

// Stage 4: Serialize to NDJSON
class NDJSONSerializer extends Transform {
  constructor() { super({ readableObjectMode: false, writableObjectMode: true }); }
  _transform(obj, _, cb) {
    this.push(JSON.stringify(obj) + '\n');
    cb();
  }
}

// --- run the pipeline ---
await pipelineP(
  createReadStream('input.csv'),
  new CSVParser(),
  new RowTransformer(),
  new RowFilter(row => row.active && row.revenue > 1000),
  new NDJSONSerializer(),
  createWriteStream('output.ndjson')
);
console.log('ETL complete');
