import cluster from 'cluster';
import { cpus } from 'os';
import process   from 'process';

const WORKER_COUNT = cpus().length;

if (cluster.isPrimary) {
  console.log(`Primary ${process.pid} starting ${WORKER_COUNT} workers`);

  // Start all workers
  for (let i = 0; i < WORKER_COUNT; i++) cluster.fork();

  // Auto-restart crashed workers
  cluster.on('exit', (worker, code, signal) => {
    if (worker.exitedAfterDisconnect) return; // intentional shutdown
    console.warn(`Worker ${worker.process.pid} died (${signal ?? code}). Restarting…`);
    cluster.fork();
  });

  // Zero-downtime rolling restart on SIGUSR2
  process.on('SIGUSR2', () => {
    const workers = Object.values(cluster.workers ?? {});
    console.log(`Rolling restart of ${workers.length} workers…`);
    rollingRestart(workers, 0);
  });

  function rollingRestart(workers, index) {
    if (index >= workers.length) {
      console.log('Rolling restart complete');
      return;
    }

    const dying = workers[index];
    if (!dying) return rollingRestart(workers, index + 1);

    console.log(`Replacing worker ${dying.process.pid}…`);

    // Fork replacement BEFORE killing old one
    const replacement = cluster.fork();

    replacement.once('listening', () => {
      console.log(`New worker ${replacement.process.pid} is listening`);

      // Now gracefully drain and kill the old worker
      dying.send('shutdown');
      dying.disconnect();

      const killTimer = setTimeout(() => dying.kill('SIGKILL'), 30_000);
      dying.once('exit', () => {
        clearTimeout(killTimer);
        console.log(`Old worker ${dying.process.pid} exited`);
        rollingRestart(workers, index + 1);
      });
    });
  }
} else {
  // Worker: start your HTTP server here
  const { createServer } = await import('http');
  const server = createServer((req, res) => res.end(`Hello from ${process.pid}`));
  server.listen(3000, () => console.log(`Worker ${process.pid} listening`));

  // Graceful shutdown: stop accepting, drain existing
  process.on('message', msg => {
    if (msg === 'shutdown') {
      console.log(`Worker ${process.pid} draining…`);
      server.close(() => process.exit(0));
      // Force exit if drain takes too long
      setTimeout(() => process.exit(1), 25_000);
    }
  });
}
