// ─── Decorator factories ─────────────────────────────────────────────────────

/** Log method calls with args and return value */
function log(target: any, key: string, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value;
  descriptor.value = async function (...args: unknown[]) {
    console.log(`[${target.constructor.name}.${key}] called with`, args);
    const result = await original.apply(this, args);
    console.log(`[${target.constructor.name}.${key}] returned`, result);
    return result;
  };
  return descriptor;
}

/** Memoize async method by JSON-serializing arguments */
function memoize(target: any, key: string, descriptor: PropertyDescriptor): PropertyDescriptor {
  const cache   = new Map<string, unknown>();
  const original = descriptor.value;
  descriptor.value = async function (...args: unknown[]) {
    const cacheKey = JSON.stringify(args);
    if (cache.has(cacheKey)) {
      console.log(`[memoize] cache hit for ${key}(${cacheKey})`);
      return cache.get(cacheKey);
    }
    const result = await original.apply(this, args);
    cache.set(cacheKey, result);
    return result;
  };
  return descriptor;
}

/** Validate that no argument is null/undefined */
function validate(target: any, key: string, descriptor: PropertyDescriptor): PropertyDescriptor {
  const original = descriptor.value;
  descriptor.value = function (...args: unknown[]) {
    const nullIdx = args.findIndex(a => a === null || a === undefined);
    if (nullIdx !== -1) {
      throw new TypeError(`${key}: argument at index ${nullIdx} must not be null/undefined`);
    }
    return original.apply(this, args);
  };
  return descriptor;
}

