// ─── Interfaces (seams for injection) ────────────────────────────────────────
interface Clock {
  now():   number;
  delay(ms: number): Promise<void>;
}

interface HttpClient {
  get<T>(url: string): Promise<T>;
  post<T>(url: string, body: unknown): Promise<T>;
}

interface MetricsRecorder {
  increment(metric: string, tags?: Record<string, string>): void;
}

// ─── Production implementations ───────────────────────────────────────────────
const RealClock: Clock = {
  now:   () => Date.now(),
  delay: ms => new Promise(r => setTimeout(r, ms)),
};

// ─── Unit under test ──────────────────────────────────────────────────────────
class RateLimitedApiClient {
  constructor(
    private readonly http:    HttpClient,
    private readonly clock:   Clock,
    private readonly metrics: MetricsRecorder,
    private readonly rpsLimit = 10
  ) {}

  async fetchWithRateLimit<T>(url: string): Promise<T> {
    const start = this.clock.now();
    try {
      const result = await this.http.get<T>(url);
      this.metrics.increment('api.success', { url });
      return result;
    } catch (err) {
      this.metrics.increment('api.error', { url });
      // Back off before retry
      await this.clock.delay(1000 / this.rpsLimit);
      throw err;
    } finally {
      this.metrics.increment('api.duration', { ms: String(this.clock.now() - start) });
    }
  }
}

// ─── Test helpers — manual mocks ─────────────────────────────────────────────
function createMockClock(startMs = 0): Clock & { advance(ms: number): void } {
  let current = startMs;
  const delays: number[] = [];
  return {
    now:     () => current,
    delay:   ms => { delays.push(ms); current += ms; return Promise.resolve(); },
    advance: ms => { current += ms; },
  };
}

function createMockHttpClient(responses: Map<string, unknown>): HttpClient {
  return {
    async get<T>(url: string) {
      const r = responses.get(url);
      if (r instanceof Error) throw r;
      return r as T;
    },
    async post<T>(_url: string, _body: unknown) { return undefined as T; },
  };
}

function createMockMetrics(): MetricsRecorder & { calls: { metric: string; tags?: object }[] } {
  const calls: { metric: string; tags?: Record<string, string> }[] = [];
  return {
    calls,
    increment(metric, tags) { calls.push({ metric, tags }); },
  };
}

// ─── Tests ───────────────────────────────────────────────────────────────────
async function runTests() {
  // Test 1: success path
  {
    const clock   = createMockClock();
    const metrics = createMockMetrics();
    const http    = createMockHttpClient(new Map([['/api/user', { id: 1 }]]));
    const client  = new RateLimitedApiClient(http, clock, metrics);

    const result = await client.fetchWithRateLimit<{ id: number }>('/api/user');
    console.assert(result.id === 1, 'Should return response');
    console.assert(metrics.calls.some(c => c.metric === 'api.success'), 'Should record success');
  }

  // Test 2: error path triggers delay
  {
    const clock   = createMockClock(1000);
    const metrics = createMockMetrics();
    const http    = createMockHttpClient(new Map([['/api/fail', new Error('503')]]));
    const client  = new RateLimitedApiClient(http, clock, metrics, 10);

    try {
      await client.fetchWithRateLimit('/api/fail');
    } catch {
      console.assert(metrics.calls.some(c => c.metric === 'api.error'), 'Should record error');
      console.assert(clock.now() === 1100, 'Should have delayed 100ms (1000/10)');
    }
  }

  console.log('All tests passed');
}

await runTests();
