/**
 * Structured clone polyfill.
 * Handles: primitives, Date, RegExp, Map, Set, Array, ArrayBuffer,
 * TypedArrays, DataView, Error subtypes, circular references.
 * Does NOT handle: DOM nodes, functions, Proxies (spec-compliant — these throw).
 */
function structuredClonePolyfill(value, options = {}) {
  const { transfer = [] } = options;
  const seen = new WeakMap();

  function clone(val) {
    // Primitives
    if (val === null || (typeof val !== 'object' && typeof val !== 'function')) {
      return val;
    }

    // Functions are not cloneable per spec
    if (typeof val === 'function') {
      throw new DOMException('Functions cannot be cloned', 'DataCloneError');
    }

    // Circular ref
    if (seen.has(val)) return seen.get(val);

    // Transferred objects — move, don't copy
    if (transfer.includes(val)) {
      if (val instanceof ArrayBuffer) {
        const copy = val.slice(0);
        // "Neutering" the original is not possible in pure JS, but we can signal it
        seen.set(val, copy);
        return copy;
      }
    }

    if (val instanceof Date)   return new Date(val.getTime());
    if (val instanceof RegExp) return new RegExp(val.source, val.flags);

    if (val instanceof Error) {
      const E = globalThis[val.constructor.name] ?? Error;
      const err = new E(val.message);
      err.stack = val.stack;
      return err;
    }

    if (val instanceof ArrayBuffer) {
      const copy = val.slice(0);
      seen.set(val, copy);
      return copy;
    }

    if (ArrayBuffer.isView(val)) {
      const bufClone = clone(val.buffer);
      const Ctor = val.constructor;
      return new Ctor(bufClone, val.byteOffset,
        val instanceof DataView ? val.byteLength : val.length);
    }

    if (val instanceof Map) {
      const m = new Map();
      seen.set(val, m);
      val.forEach((v, k) => m.set(clone(k), clone(v)));
      return m;
    }

    if (val instanceof Set) {
      const s = new Set();
      seen.set(val, s);
      val.forEach(v => s.add(clone(v)));
      return s;
    }

    if (Array.isArray(val)) {
      const arr = new Array(val.length);
      seen.set(val, arr);
      for (let i = 0; i < val.length; i++) arr[i] = clone(val[i]);
      return arr;
    }

    // Plain objects (no prototype support — spec-compliant behavior)
    const obj = {};
    seen.set(val, obj);
    for (const key of Reflect.ownKeys(val)) {
      obj[key] = clone(val[key]);
    }
    return obj;
  }

  return clone(value);
}

// Install as global polyfill if not available
if (typeof globalThis.structuredClone === 'undefined') {
  globalThis.structuredClone = structuredClonePolyfill;
}

// --- tests ---
const orig = { a: 1, b: new Map([['x', new Set([1,2,3])]]), c: new Date('2024-01-01') };
orig.self = orig; // circular

const copy = structuredClonePolyfill(orig);
console.log(copy.a);                     // 1
console.log(copy.b.get('x') instanceof Set); // true
console.log(copy.c.toISOString());      // '2024-01-01T00:00:00.000Z'
console.log(copy.self === copy);        // true (circular preserved)
console.log(copy.self !== orig.self);   // true (deep copy)
