// ─── Core types ────────────────────────────────────────────────────────────────
type EntityId = string | number;
interface Entity { id: EntityId; }

type WhereClause<T> = Partial<{ [K in keyof T]: T[K] | ((v: T[K]) => boolean) }>;

interface FindOptions<T> {
  where?:    WhereClause<T>;
  orderBy?:  Partial<Record<keyof T, 'asc' | 'desc'>>;
  limit?:    number;
  offset?:   number;
}

// ─── In-memory Repository base ─────────────────────────────────────────────────
abstract class Repository<T extends Entity> {
  protected store: Map<EntityId, T>;

  constructor(store = new Map<EntityId, T>()) {
    this.store = store;
  }

  async findById(id: EntityId): Promise<T | undefined> {
    return this.store.get(id);
  }

  async findOne(opts: FindOptions<T>): Promise<T | undefined> {
    return (await this.findMany(opts))[0];
  }

  async findMany(opts: FindOptions<T> = {}): Promise<T[]> {
    let results = [...this.store.values()];

    if (opts.where) {
      results = results.filter(entity =>
        (Object.entries(opts.where!) as [keyof T, any][]).every(([k, matcher]) =>
          typeof matcher === 'function' ? matcher(entity[k]) : entity[k] === matcher
        )
      );
    }

    if (opts.orderBy) {
      for (const [key, dir] of Object.entries(opts.orderBy)) {
        results.sort((a, b) => {
          const av = (a as any)[key], bv = (b as any)[key];
          return (av < bv ? -1 : av > bv ? 1 : 0) * (dir === 'desc' ? -1 : 1);
        });
      }
    }

    const start = opts.offset ?? 0;
    const end   = opts.limit  ? start + opts.limit : undefined;
    return results.slice(start, end);
  }

  async save(entity: T): Promise<T> {
    this.store.set(entity.id, { ...entity });
    return entity;
  }

  async delete(id: EntityId): Promise<boolean> {
    return this.store.delete(id);
  }

  async count(where?: WhereClause<T>): Promise<number> {
    return (await this.findMany({ where })).length;
  }
}

// ─── Unit of Work ──────────────────────────────────────────────────────────────
class UnitOfWork {
  private snapshots: Map<Repository<any>, Map<EntityId, any>> = new Map();

  track<T extends Entity>(repo: Repository<any>): void {
    // Snapshot current state
    this.snapshots.set(repo, new Map((repo as any).store));
  }

  async commit(): Promise<void> {
    this.snapshots.clear(); // persist — in-memory store already updated
  }

  async rollback(): Promise<void> {
    for (const [repo, snapshot] of this.snapshots) {
      (repo as any).store = new Map(snapshot);
    }
    this.snapshots.clear();
  }
}

// ─── Concrete repo + usage ─────────────────────────────────────────────────────
interface User extends Entity { id: string; name: string; age: number; active: boolean; }

class UserRepository extends Repository<User> {}

const users = new UserRepository();

await users.save({ id: 'u1', name: 'Alice', age: 30, active: true });
await users.save({ id: 'u2', name: 'Bob',   age: 22, active: false });
await users.save({ id: 'u3', name: 'Carol', age: 28, active: true });

const active = await users.findMany({
  where:   { active: true },
  orderBy: { name: 'asc' },
});
console.log(active.map(u => u.name)); // ['Alice', 'Carol']

const uow = new UnitOfWork();
uow.track(users);
await users.save({ id: 'u4', name: 'Dave', age: 19, active: true });
console.log(await users.count()); // 4
await uow.rollback();
console.log(await users.count()); // 3 — Dave rolled back
