// Define states and transitions as a type-level graph
type FSMConfig = {
  [State in string]: {
    [Event in string]: string; // event → next state
  };
};

// Extract all valid states from a config
type States<C extends FSMConfig> = keyof C;

// Events valid in a particular state
type ValidEvents<C extends FSMConfig, S extends States<C>> = keyof C[S];

// Next state after sending event E in state S
type NextState<C extends FSMConfig, S extends States<C>, E extends ValidEvents<C, S>> =
  C[S][E] & States<C>;

// ─── Concrete traffic-light FSM ────────────────────────────────────────────────
const trafficConfig = {
  red:    { timer: 'green'  },
  green:  { timer: 'yellow' },
  yellow: { timer: 'red', emergency: 'red' },
} as const satisfies FSMConfig;

type TrafficConfig = typeof trafficConfig;
type TrafficState  = States<TrafficConfig>;

class StateMachine<C extends FSMConfig, S extends States<C>> {
  private readonly config: C;
  private _state: S;
  private history: States<C>[] = [];

  constructor(config: C, initial: S) {
    this.config = config;
    this._state = initial;
  }

  get state(): S { return this._state; }

  // Only accepts events valid in the CURRENT state — enforced at compile time
  send<E extends ValidEvents<C, S>>(event: E): StateMachine<C, NextState<C, S, E>> {
    const next = this.config[this._state][event as string] as NextState<C, S, E>;
    this.history.push(this._state);
    this._state = next as unknown as S;
    return this as unknown as StateMachine<C, NextState<C, S, E>>;
  }

  can<E extends string>(event: E): event is ValidEvents<C, S> & E {
    return event in this.config[this._state];
  }

  getHistory(): States<C>[] { return [...this.history]; }
}

// ─── Usage ────────────────────────────────────────────────────────────────────
const light = new StateMachine(trafficConfig, 'red' as const);

const afterGreen  = light.send('timer');              // state: 'green'
const afterYellow = afterGreen.send('timer');         // state: 'yellow'
const afterRed    = afterYellow.send('emergency');    // state: 'red'

console.log(afterRed.state);          // 'red'
console.log(afterRed.getHistory());  // ['red', 'green', 'yellow']

// Type error — 'emergency' is not a valid event in 'green'
// afterGreen.send('emergency');  // Error!

// Runtime guard
console.log(light.can('timer'));     // true
console.log(light.can('emergency')); // false (not valid in 'red')
