class LRUNode {
  constructor(key, value) {
    this.key   = key;
    this.value = value;
    this.prev  = null;
    this.next  = null;
  }
}

class LRUCache {
  #capacity;
  #map;   // key → node
  #head;  // dummy head (most recently used side)
  #tail;  // dummy tail (least recently used side)
  #size = 0;

  constructor(capacity) {
    if (capacity < 1) throw new RangeError('Capacity must be >= 1');
    this.#capacity = capacity;
    this.#map      = new Map();
    // Sentinel nodes eliminate null checks
    this.#head = new LRUNode(null, null);
    this.#tail = new LRUNode(null, null);
    this.#head.next = this.#tail;
    this.#tail.prev = this.#head;
  }

  get(key) {
    const node = this.#map.get(key);
    if (!node) return -1;
    this.#moveToFront(node);
    return node.value;
  }

  put(key, value) {
    if (this.#map.has(key)) {
      const node  = this.#map.get(key);
      node.value  = value;
      this.#moveToFront(node);
    } else {
      const node = new LRUNode(key, value);
      this.#map.set(key, node);
      this.#insertFront(node);
      this.#size++;

      if (this.#size > this.#capacity) {
        const evicted = this.#tail.prev;
        this.#remove(evicted);
        this.#map.delete(evicted.key);
        this.#size--;
      }
    }
  }

  #remove(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }

  #insertFront(node) {
    node.prev       = this.#head;
    node.next       = this.#head.next;
    this.#head.next.prev = node;
    this.#head.next      = node;
  }

  #moveToFront(node) {
    this.#remove(node);
    this.#insertFront(node);
  }

  get size()     { return this.#size; }
  get capacity() { return this.#capacity; }

  // Debug: snapshot of keys from MRU to LRU
  keys() {
    const result = [];
    let cur = this.#head.next;
    while (cur !== this.#tail) { result.push(cur.key); cur = cur.next; }
    return result;
  }
}

// --- tests ---
const cache = new LRUCache(3);
cache.put('a', 1); cache.put('b', 2); cache.put('c', 3);
console.log(cache.get('a'));  // 1 — 'a' promoted to MRU
cache.put('d', 4);            // evicts 'b' (LRU)
console.log(cache.keys());    // ['d', 'a', 'c']
console.log(cache.get('b'));  // -1 — evicted
