class DeadLetterQueue {
  #messages = [];

  push(message) {
    this.#messages.push({ ...message, deadAt: Date.now() });
    console.error(`[DLQ] Message dead after ${message.attempts} attempts:`, message.topic, message.payload);
  }

  drain() {
    const msgs = [...this.#messages];
    this.#messages = [];
    return msgs;
  }

  get size() { return this.#messages.length; }
}

class RetryablePubSub {
  #subs = new Map();  // topic → handler[]
  #dlq;
  #maxRetries;
  #backoff;

  constructor({ maxRetries = 3, backoff = n => 100 * 2 ** n, dlq = new DeadLetterQueue() } = {}) {
    this.#maxRetries = maxRetries;
    this.#backoff    = backoff;
    this.#dlq        = dlq;
  }

  get dlq() { return this.#dlq; }

  subscribe(topic, handler) {
    if (!this.#subs.has(topic)) this.#subs.set(topic, []);
    this.#subs.get(topic).push(handler);
    return () => {
      const handlers = this.#subs.get(topic) ?? [];
      this.#subs.set(topic, handlers.filter(h => h !== handler));
    };
  }

  async publish(topic, payload) {
    const handlers = this.#subs.get(topic) ?? [];

    await Promise.allSettled(
      handlers.map(handler => this.#deliver({ topic, payload, handler }))
    );
  }

  async #deliver(ctx, attempt = 0) {
    const { topic, payload, handler } = ctx;
    try {
      await handler(payload, { topic, attempt });
    } catch (error) {
      if (attempt < this.#maxRetries) {
        const delay = this.#backoff(attempt);
        console.warn(`[pubsub] Retry ${attempt + 1}/${this.#maxRetries} for ${topic} in ${delay}ms`);
        await new Promise(r => setTimeout(r, delay));
        return this.#deliver(ctx, attempt + 1);
      }
      // Move to DLQ with full context
      this.#dlq.push({
        topic,
        payload,
        attempts: attempt + 1,
        lastError: { message: error.message, stack: error.stack },
        handler:  handler.name || 'anonymous',
        failedAt: Date.now(),
      });
    }
  }
}

// --- usage ---
const bus = new RetryablePubSub({ maxRetries: 2, backoff: n => 50 * 2 ** n });
let callCount = 0;

bus.subscribe('order.placed', async (payload) => {
  callCount++;
  if (callCount < 3) throw new Error('Downstream service unavailable');
  console.log('Order processed:', payload.orderId);
});

bus.subscribe('order.placed', async (payload) => {
  // This one always succeeds
  console.log('Audit logged:', payload.orderId);
});

await bus.publish('order.placed', { orderId: 'O-001', total: 99.99 });

console.log('DLQ size:', bus.dlq.size); // 1 (first handler went to DLQ)
console.log('DLQ messages:', bus.dlq.drain());
