import { Readable, Writable, pipeline } from 'stream';
import { promisify }                    from 'util';

const pipelineAsync = promisify(pipeline);

/**
 * A Writable that simulates a slow consumer and demonstrates
 * proper backpressure propagation.
 */
class SlowWritable extends Writable {
  #processTimeMs;
  #written = 0;

  constructor(processTimeMs = 100, opts = {}) {
    super({ ...opts, highWaterMark: 3 }); // tiny HWM to trigger backpressure quickly
    this.#processTimeMs = processTimeMs;
  }

  _write(chunk, _encoding, callback) {
    this.#written++;
    const n = this.#written;
    console.log(`  [write #${n}] processing ${chunk.length} bytes (queue: ${this.writableLength})`);
    // Simulate async slow processing (DB insert, API call, etc.)
    setTimeout(() => {
      console.log(`  [write #${n}] done`);
      callback(); // Signal that we're ready for next chunk
    }, this.#processTimeMs);
  }

  _final(callback) {
    console.log(`[writable] all done, total writes: ${this.#written}`);
    callback();
  }
}

/**
 * A Readable that respects backpressure by checking push()'s return value.
 */
class FastReadable extends Readable {
  #total;
  #sent = 0;
  #pauses = 0;

  constructor(totalChunks = 20, opts = {}) {
    super({ ...opts, highWaterMark: 2 });
    this.#total = totalChunks;
  }

  _read(_size) {
    if (this.#sent >= this.#total) {
      this.push(null); // EOF
      console.log(`[readable] exhausted after ${this.#pauses} backpressure pauses`);
      return;
    }

    const chunk  = Buffer.alloc(1024, this.#sent % 256);
    const canContinue = this.push(chunk);
    this.#sent++;

    console.log(`[readable] pushed chunk ${this.#sent} — canContinue: ${canContinue}`);

    if (!canContinue) {
      // Backpressure: stop producing until 'drain' event
      // _read() won't be called again until the consumer drains
      this.#pauses++;
      console.log(`[readable] *** BACKPRESSURE — pausing (pause #${this.#pauses}) ***`);
    }
  }
}

// pipeline() handles backpressure and error propagation automatically
const source = new FastReadable(20);
const sink   = new SlowWritable(80);

await pipelineAsync(source, sink);
console.log('Pipeline complete');
