```typescript
interface TrieNode<V> {
  children: Map<string, TrieNode<V>>;
  value?:   V;
  isEnd:    boolean;
}

class Trie<V> {
  private root: TrieNode<V> = { children: new Map(), isEnd: false };
  private _size = 0;

  private makeNode(): TrieNode<V> {
    return { children: new Map(), isEnd: false };
  }

  set(key: string, value: V): this {
    let node = this.root;
    for (const ch of key) {
      if (!node.children.has(ch)) {
        node.children.set(ch, this.makeNode());
      }
      node = node.children.get(ch)!;
    }
    if (!node.isEnd) this._size++;
    node.isEnd = true;
    node.value = value;
    return this;
  }

  get(key: string): V | undefined {
    const node = this.#traverse(key);
    return node?.isEnd ? node.value : undefined;
  }

  has(key: string): boolean {
    const node = this.#traverse(key);
    return node?.isEnd === true;
  }

  delete(key: string): boolean {
    return this.#delete(this.root, key, 0);
  }

  // All entries with the given prefix
  prefixSearch(prefix: string): [string, V][] {
    const node = this.#traverse(prefix);
    if (!node) return [];
    const results: [string, V][] = [];
    this.#collect(node, prefix, results);
    return results;
  }

  // Longest prefix of `key` that exists in the trie
  longestPrefixOf(key: string): string {
    let node    = this.root;
    let longest = '';
    let current = '';
    for (const ch of key) {
      const child = node.children.get(ch);
      if (!child) break;
      current += ch;
      if (child.isEnd) longest = current;
      node = child;
    }
    return longest;
  }

  get size() { return this._size; }

  #traverse(key: string): TrieNode<V> | null {
    let node = this.root;
    for (const ch of key) {
      const child = node.children.get(ch);
      if (!child) return null;
      node = child;
    }
    return node;
  }

  #collect(node: TrieNode<V>, prefix: string, acc: [string, V][]) {
    if (node.isEnd && node.value !== undefined) acc.push([prefix, node.value]);
    for (const [ch, child] of node.children) {
      this.#collect(child, prefix + ch, acc);
    }
  }

  #delete(node: TrieNode<V>, key: string, depth: number): boolean {
    if (depth === key.length) {
      if (!node.isEnd) return false;
      node.isEnd  = false;
      node.value  = undefined;
      this._size--;
      return true;
    }
    const ch    = key[depth];
    const child = node.children.get(ch);
    if (!child) return false;
    const deleted = this.#delete(child, key, depth + 1);
    if (deleted && !child.isEnd && child.children.size === 0) {
      node.children.delete(ch); // prune empty branch
    }
    return deleted;
  }

  toJSON(): object {
    const serialize = (n: TrieNode<V>): object => ({
      v: n.value,
      e: n.isEnd,
      c: Object.fromEntries([...n.children].map(([k, v]) => [k, serialize(v)])),
    });
    return serialize(this.root);
  }
}

// --- usage ---
const trie = new Trie<number>();
['apple', 'app', 'application', 'apply', 'apt', 'banana'].forEach((w, i) => trie.set(w, i));

console.log(trie.get('app'));             // 1
console.log(trie.prefixSearch('app').map(([k]) => k)); // ['app', 'apple', 'application', 'apply']
console.log(trie.longestPrefixOf('application-server')); // 'application'
console.log(trie.size);                  // 6
trie.delete('app');
console.log(trie.has('app'));            // false
console.log(trie.has('apple'));          // true
