/**
 * Tagged template for safe parameterized SQL.
 * Returns { text, values } compatible with node-postgres (pg) and most SQL clients.
 *
 * Usage:
 *   const { text, values } = sql`SELECT * FROM users WHERE id = ${userId} AND active = ${true}`
 *   // text:   'SELECT * FROM users WHERE id = $1 AND active = $2'
 *   // values: [userId, true]
 */
function sql(strings, ...values) {
  let text = '';
  strings.forEach((str, i) => {
    text += str;
    if (i < values.length) {
      text += `$${i + 1}`;
    }
  });
  return { text: text.trim(), values };
}

// Extension: support raw SQL fragments (for ORDER BY columns, etc.)
function raw(str) {
  return { __raw: true, value: str };
}

function sqlWithRaw(strings, ...values) {
  let text = '';
  const params = [];

  strings.forEach((str, i) => {
    text += str;
    if (i < values.length) {
      const v = values[i];
      if (v && typeof v === 'object' && v.__raw) {
        text += v.value; // inject raw SQL — caller's responsibility to sanitize
      } else {
        params.push(v);
        text += `$${params.length}`;
      }
    }
  });

  return { text: text.trim(), values: params };
}

// Composable: embed one query result into another
function subquery({ text, values }, offset = 0) {
  const shifted = text.replace(/\$(\d+)/g, (_, n) => `$${parseInt(n, 10) + offset}`);
  return { text: shifted, values };
}

// --- usage ---
const userId   = 42;
const minScore = 0.8;
const q1       = sql`SELECT * FROM users WHERE id = ${userId} AND score > ${minScore}`;
console.log(q1);
// { text: 'SELECT * FROM users WHERE id = $1 AND score > $2', values: [42, 0.8] }

// With raw (for ORDER BY, table names validated elsewhere)
const col  = 'name'; // must come from a whitelist!
const q2   = sqlWithRaw`SELECT id, ${raw(col)} FROM users ORDER BY ${raw(col)} ASC LIMIT ${10}`;
console.log(q2);
// { text: 'SELECT id, name FROM users ORDER BY name ASC LIMIT $1', values: [10] }

// Async execution (node-postgres)
async function getUser(pool, id) {
  const query  = sql`SELECT * FROM users WHERE id = ${id}`;
  const { rows } = await pool.query(query);
  return rows[0];
}
