/**
 * Safe handle pattern: the JS object holds a token.
 * The actual resource is stored in a separate registry-owned map.
 * When the JS handle is GC'd, FinalizationRegistry cleans up the resource.
 */
const resourceMap = new Map(); // token → resource
let tokenSeq      = 0;

const registry = new FinalizationRegistry(token => {
  const resource = resourceMap.get(token);
  if (resource) {
    console.log(`[GC] Auto-closing resource token=${token}:`, resource.description);
    resource.close?.();
    resourceMap.delete(token);
  }
});

function createManagedHandle(resource) {
  const token = ++tokenSeq;
  resourceMap.set(token, resource);

  const handle = Object.freeze({
    // Explicit close — also unregisters from the registry
    close() {
      const r = resourceMap.get(token);
      if (r) {
        r.close?.();
        resourceMap.delete(token);
        registry.unregister(unregisterToken);
        console.log(`[explicit] closed resource token=${token}`);
      }
    },
    use(fn) {
      const r = resourceMap.get(token);
      if (!r) throw new Error('Resource already closed');
      return fn(r);
    },
    get isOpen() { return resourceMap.has(token); },
  });

  // An unregister token we hold onto — must NOT be `handle` itself
  const unregisterToken = {};
  registry.register(handle, token, unregisterToken);

  return handle;
}

// --- Simulate a file handle ------------------------------------------------
function openFile(path) {
  const fd = { path, fd: Math.floor(Math.random() * 1000), description: `File:${path}` };
  fd.close    = () => console.log(`  [fd] closed fd=${fd.fd} path=${fd.path}`);
  fd.readLine = () => `line from ${fd.path}`;
  console.log(`[open] fd=${fd.fd} path=${fd.path}`);
  return createManagedHandle(fd);
}

// Usage 1: explicit close (preferred)
{
  const f = openFile('/etc/hosts');
  console.log(f.use(fd => fd.readLine()));
  f.close(); // explicit — no GC needed
}

// Usage 2: forgot to close — GC will clean it up eventually
{
  let f = openFile('/tmp/leak.txt');
  f.use(fd => console.log(fd.readLine()));
  f = null; // lost reference
  // FinalizationRegistry will call close() after GC
}

// Trigger GC in Node.js for demonstration:
if (global.gc) {
  global.gc();
  console.log('GC triggered — check for auto-close log');
} else {
  console.log('Run with --expose-gc to observe auto-cleanup');
}
