// Event map: namespaced keys → payload types
interface AppEventMap {
  'user:login':       { userId: string; ip: string };
  'user:logout':      { userId: string };
  'user:updated':     { userId: string; changes: Partial<{ name: string; email: string }> };
  'order:created':    { orderId: string; total: number };
  'order:fulfilled':  { orderId: string; trackingId: string };
  'system:error':     Error;
  'system:startup':   { version: string };
}

type EventKey = keyof AppEventMap;

// Extract namespace from 'ns:event' → 'ns'
type Namespace<K extends string> = K extends `${infer NS}:${string}` ? NS : never;
type AllNamespaces = Namespace<EventKey>; // 'user' | 'order' | 'system'

// All events in a namespace
type EventsInNS<NS extends string> = {
  [K in EventKey]: K extends `${NS}:${string}` ? K : never;
}[EventKey];

type Handler<K extends EventKey> = (payload: AppEventMap[K], event: K) => void;

class NamespacedEventBus {
  private handlers = new Map<string, Set<{ fn: Handler<any>; once: boolean }>>();

  on<K extends EventKey>(event: K, handler: Handler<K>): () => void {
    return this.#add(event, handler, false);
  }

  once<K extends EventKey>(event: K, handler: Handler<K>): () => void {
    return this.#add(event, handler, true);
  }

  // Subscribe to all events in a namespace
  onNamespace<NS extends AllNamespaces>(
    ns:      NS,
    handler: <K extends EventsInNS<NS>>(payload: AppEventMap[K], event: K) => void
  ): () => void {
    return this.#add(`${ns}:*`, handler as any, false);
  }

  emit<K extends EventKey>(event: K, payload: AppEventMap[K]): void {
    // Exact listeners
    this.#dispatch(event, event, payload);

    // Wildcard listeners for this namespace
    const ns = event.split(':')[0];
    this.#dispatch(`${ns}:*`, event, payload);
  }

  #add(pattern: string, fn: Handler<any>, once: boolean): () => void {
    if (!this.handlers.has(pattern)) this.handlers.set(pattern, new Set());
    const entry = { fn, once };
    this.handlers.get(pattern)!.add(entry);
    return () => this.handlers.get(pattern)?.delete(entry);
  }

  #dispatch(pattern: string, event: EventKey, payload: unknown): void {
    const set = this.handlers.get(pattern);
    if (!set) return;
    for (const entry of set) {
      entry.fn(payload, event);
      if (entry.once) set.delete(entry);
    }
  }
}

// --- usage ---
const bus = new NamespacedEventBus();

// Exact subscription
const off = bus.on('user:login', ({ userId, ip }) => {
  console.log(`User ${userId} logged in from ${ip}`);
});

// Namespace wildcard
bus.onNamespace('order', (payload, event) => {
  console.log(`Order event [${event}]:`, payload);
});

// Once
bus.once('system:startup', ({ version }) => {
  console.log(`System started — v${version}`);
});

bus.emit('user:login',      { userId: 'u1', ip: '127.0.0.1' });
bus.emit('order:created',   { orderId: 'o1', total: 49.99 });
bus.emit('order:fulfilled', { orderId: 'o1', trackingId: 'T-123' });
bus.emit('system:startup',  { version: '2.0.0' });
bus.emit('system:startup',  { version: '2.0.0' }); // once — no output

off(); // unsubscribe user:login
